import { Component } from '@angular/core';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive],
  template: `
    <header class="app-header">
      <div class="brand">
        <span class="brand-icon">⚙️</span>
        <span class="brand-name">AdminProcesos</span>
      </div>
      <nav>
        <a routerLink="/recibeoc" routerLinkActive="active">Recepción OC</a>
      </nav>
    </header>
    <main class="app-main">
      <router-outlet />
    </main>
  `,
  styles: [`
    .app-header {
      display: flex; align-items: center; justify-content: space-between;
      padding: .75rem 1.5rem;
      background: #1a6fc4; color: #fff;
      box-shadow: 0 2px 6px rgba(0,0,0,.15);
    }
    .brand { display: flex; align-items: center; gap: .5rem; }
    .brand-icon { font-size: 1.4rem; }
    .brand-name { font-size: 1.15rem; font-weight: 700; letter-spacing: .5px; }
    nav a {
      color: rgba(255,255,255,.85); text-decoration: none;
      padding: .35rem .8rem; border-radius: 5px;
      font-size: .9rem; font-weight: 500;
      transition: background .15s;
      &:hover, &.active { background: rgba(255,255,255,.18); color: #fff; }
    }
    .app-main { padding: 1.5rem; max-width: 1400px; margin: 0 auto; }
  `]
})
export class AppComponent {}
